// Declare which package this class belongs to
package com.school.model;

// Import Date from Java's utility package
import java.util.Date;

// Import our own class from another package
import com.school.util.StudentIdGenerator;

public class Student {
    private String name;
    private Date enrollmentDate;
    private String studentId;

    public Student(String name) {
        this.name = name;
        // Use the imported class from another package
        this.studentId = StudentIdGenerator.generate();
        this.enrollmentDate = new Date();
    }

    public void printInfo() {
        System.out.println(name + " - " + studentId);
    }
}
// Expected: new Student("Luis").printInfo();
// Output: Luis - S-2024-0001
